module top_module(in1, in2, c, obf_aluout);input [2:0] in1, in2;
input [1:0] c;
output reg [2:0] obf_aluout;
always @ (in1, in2, c)
    begin
        case (c)
            2'b11:  obf_aluout = in1 + in2;
            2'b10:  obf_aluout = in1 - in2;
            2'b01:  obf_aluout = in1 & in2;
            2'b00:  obf_aluout = in1 ^ in2;
        endcase
    end
endmodule
